describe("reduce", () => {
  it("should accumulate values and call callback with final result", (done) => {
    const values = [1, 2, 3, 4, 5];
    let i = 0;
    const source = (end: any, cb: Function) => {
      if (end) return cb(end);
      if (i >= values.length) return cb(true);
      cb(null, values[i++]);
    };
    const sink = reduce((acc: number, x: number) => acc + x, 0, (err: any, result: number) => {
      expect(err).toBeNull();
      expect(result).toBe(15);
      done();
    });
    sink(source);
  });
});
```

